package com.google.gson;
import static org.junit.jupiter.api.Assertions.assertThrows;
import static org.junit.jupiter.api.Assertions.assertDoesNotThrow;

import org.junit.jupiter.api.Test;

import java.lang.reflect.InvocationTargetException;
import java.lang.reflect.Method;

public class GsonTest {

  @Test
  void testCheckValidFloatingPoint_validValues() throws Exception {
    Method method = Gson.class.getDeclaredMethod("checkValidFloatingPoint", double.class);
    method.setAccessible(true);

    // Valid double values should not throw
    assertDoesNotThrow(() -> method.invoke(null, 0.0));
    assertDoesNotThrow(() -> method.invoke(null, 1.0));
    assertDoesNotThrow(() -> method.invoke(null, -1.0));
    assertDoesNotThrow(() -> method.invoke(null, Double.MAX_VALUE));
    assertDoesNotThrow(() -> method.invoke(null, Double.MIN_VALUE));
  }

  @Test
  void testCheckValidFloatingPoint_nanValue() throws Exception {
    Method method = Gson.class.getDeclaredMethod("checkValidFloatingPoint", double.class);
    method.setAccessible(true);

    InvocationTargetException thrown = assertThrows(InvocationTargetException.class,
        () -> method.invoke(null, Double.NaN));
    Throwable cause = thrown.getCause();
    assertThrows(IllegalArgumentException.class, () -> { throw cause; });
  }

  @Test
  void testCheckValidFloatingPoint_positiveInfinity() throws Exception {
    Method method = Gson.class.getDeclaredMethod("checkValidFloatingPoint", double.class);
    method.setAccessible(true);

    InvocationTargetException thrown = assertThrows(InvocationTargetException.class,
        () -> method.invoke(null, Double.POSITIVE_INFINITY));
    Throwable cause = thrown.getCause();
    assertThrows(IllegalArgumentException.class, () -> { throw cause; });
  }

  @Test
  void testCheckValidFloatingPoint_negativeInfinity() throws Exception {
    Method method = Gson.class.getDeclaredMethod("checkValidFloatingPoint", double.class);
    method.setAccessible(true);

    InvocationTargetException thrown = assertThrows(InvocationTargetException.class,
        () -> method.invoke(null, Double.NEGATIVE_INFINITY));
    Throwable cause = thrown.getCause();
    assertThrows(IllegalArgumentException.class, () -> { throw cause; });
  }
}
